import { Box, IconButton, useTheme, Typography } from "@mui/material";
import { useContext, useState, useEffect } from "react";
import { ColorModeContext } from "../../theme";
import { useLocation } from "react-router-dom";

const Topbar = ({ isCollapsed, handleLogout }) => {
  const theme = useTheme();
  const colorMode = useContext(ColorModeContext);
  const location = useLocation();
  const [pageTitle, setPageTitle] = useState("");

  useEffect(() => {
    switch (location.pathname) {
      case "/":
        setPageTitle("Dashboard");
        break;
      case "/team":
        setPageTitle("Manage Team");
        break;
      case "/upload":
        setPageTitle("Files Upload");
        break;
      case "/treecount":
        setPageTitle("Tree Count");
        break;
      case "/area":
        setPageTitle("Area Data");
        break;
      case "/potree":
        setPageTitle("Point Cloud Viewer");
        break;
      default:
        // Handle dynamic paths like /potree?url=... if necessary
        if (location.pathname.startsWith("/potree")) {
            setPageTitle("Point Cloud Viewer");
        } else {
            setPageTitle("Dashboard"); // Default title
        }
    }
  }, [location.pathname]);

  return (
    <Box
      display="flex"
      justifyContent="space-between"
      p={2}
      sx={{
        marginLeft: isCollapsed ? "80px" : "270px",
        transition: "margin-left 0.3s ease",
      }}
    >
      {/* PAGE TITLE */}
      <Box display="flex" alignItems="center" minWidth="200px">
        <Typography variant="h3" fontWeight="bold" paddingLeft={"15px"}>
          {pageTitle}
        </Typography>
      </Box>

      {/* COMPANY LOGO */}
      <Box
        display="flex"
        justifyContent="center"
        alignItems="center"
        ml="-120px"
        height="100%" // Ensure logo box takes full height
      >
        <img
          src="../../assets/logo.png"
          alt="Company Logo"
          style={{ maxHeight: "80px", maxWidth: "150px" }} //Added max width
        />
      </Box>

      {/* ICONS */}
      <Box display="flex" alignItems="center">
        <IconButton onClick={colorMode.toggleColorMode}>
          {theme.palette.mode === "dark" ? (
            <span className="material-symbols-outlined">dark_mode</span>
          ) : (
            <span className="material-symbols-outlined">light_mode</span>
          )}
        </IconButton>
        <IconButton onClick={handleLogout} title="Logout">
          <span className="material-symbols-outlined">logout</span>
        </IconButton>
      </Box>
    </Box>
  );
};

export default Topbar;
